INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e9706f56-6eeb-44a5-ba73-d7d28bd5c722',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Tensor Ops — Broadcasting, Shapes, and GPU Placement$escape$,
  $escape$TensorFlow tensors are immutable, typed N-dimensional arrays. Every operation produces a new tensor — never mutates in place. Broadcasting follows NumPy semantics: dimensions are aligned from the right, and size-1 dims expand to match. A shape `[3,1]` tensor added to `[1,4]` yields `[3,4]` without materializing copies.

Device placement is explicit via `tf.device`. By default, TensorFlow greedily places ops on the first available GPU. Use `tf.config.list_physical_devices('GPU')` to inspect available devices, and wrap ops in `with tf.device('/GPU:0'):` to pin execution. Cross-device tensor copies are implicit but expensive — minimize them by keeping entire forward passes on a single device.

`tf.function` compiles a Python function into a static graph via tracing, which unlocks XLA fusion and eliminates Python overhead. The first call traces; subsequent calls reuse the graph. Avoid Python side effects inside `tf.function` — they run only on trace, not on every call. Use `tf.print` instead of `print` for in-graph logging.$escape$,
  $escape$import tensorflow as tf

# Broadcasting: [3,1] + [1,4] => [3,4]
a = tf.constant([[1.0], [2.0], [3.0]])   # shape [3,1]
b = tf.constant([[10.0, 20.0, 30.0, 40.0]])  # shape [1,4]
c = a + b  # shape [3,4], no copies allocated

# Explicit GPU placement
with tf.device('/GPU:0'):
    x = tf.random.normal([1024, 1024])
    y = tf.matmul(x, tf.transpose(x))

# Compiled graph via tf.function
@tf.function
def normalize(t: tf.Tensor) -> tf.Tensor:
    mean, variance = tf.nn.moments(t, axes=[0])
    return tf.nn.batch_normalization(t, mean, variance, None, None, 1e-8)

result = normalize(tf.random.normal([512, 128]))
tf.print("Output shape:", tf.shape(result))$escape$,
