INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '597eec6a-829d-46eb-934f-397e01f82dbe',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Custom Layers — Extending tf.keras.layers.Layer the Right Way$escape$,
  $escape$TensorFlow's layer abstraction lives in `tf.keras.layers.Layer`. When built-in layers don't fit, subclass it directly — override `build()` to create weight tensors (called once, on first input shape) and `call()` for the forward pass. This separation matters: `build()` gives you `self.add_weight()` with proper initializer and regularizer support, while `call()` keeps computation clean and traceable by `tf.function`. Activation functions are just callables — pass `tf.nn.gelu` or a string like `'swish'` to `tf.keras.activations.get()` for runtime resolution, or compose them inline inside `call()`. For reusable blocks, nest layers as attributes in `__init__` so Keras tracks their weights automatically via `self._trainable_weights`. Skip manual weight registration — Keras walks your attributes. Mark non-training paths with `call(self, x, training=False)` and gate `tf.keras.layers.Dropout` or `BatchNormalization` behavior on that flag. Custom layers compose identically to built-ins inside `tf.keras.Sequential` or the Functional API, and they serialize cleanly if you implement `get_config()`.$escape$,
  $escape$import tensorflow as tf

class GatedLinearUnit(tf.keras.layers.Layer):
    def __init__(self, units, **kwargs):
        super().__init__(**kwargs)
        self.dense = tf.keras.layers.Dense(units * 2)

    def build(self, input_shape):
        self.dense.build(input_shape)
        super().build(input_shape)

    def call(self, x, training=False):
        projected = self.dense(x)
        values, gates = tf.split(projected, 2, axis=-1)
        return values * tf.nn.sigmoid(gates)

    def get_config(self):
        return {**super().get_config(), 'units': self.dense.units // 2}

# Drop-in with Functional API
inputs = tf.keras.Input(shape=(128,))
outputs = GatedLinearUnit(64)(inputs)
model = tf.keras.Model(inputs, outputs)$escape$,
  $escape$python$escape$,
