INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b9ac6399-6905-4cbb-a4f8-5b8950751aa1',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Loss Functions — Picking Right and Writing Your Own$escape$,
  $escape$TensorFlow's `tf.keras.losses` covers most supervised learning needs, but the wrong choice silently kills training. Use `SparseCategoricalCrossentropy` when your labels are integers, `CategoricalCrossentropy` when they're one-hot — mixing them is a silent bug that won't raise an error. Set `from_logits=True` whenever your final layer has no activation; skipping this causes numerically unstable log computations. For regression, prefer `Huber` over `MeanSquaredError` when outliers are present — it's quadratic near zero, linear beyond a delta threshold.

When built-ins don't fit — say, a focal loss for class imbalance or a custom ranking objective — subclass `tf.keras.losses.Loss`. Override `call(y_true, y_pred)` and return a per-sample tensor; Keras handles reduction automatically based on the `reduction` argument you pass to `super().__init__()`. Avoid plain Python ops inside `call` — use `tf.math` equivalents so the function stays inside the graph and supports `tf.function` tracing. Always test your custom loss with `tf.debugging.assert_near` against a NumPy reference before plugging it into `model.compile`.$escape$,
  $escape$import tensorflow as tf

class FocalLoss(tf.keras.losses.Loss):
    def __init__(self, gamma=2.0, alpha=0.25, **kwargs):
        super().__init__(**kwargs)
        self.gamma = gamma
        self.alpha = alpha

    def call(self, y_true, y_pred):
        bce = tf.keras.losses.binary_crossentropy(
            y_true, y_pred, from_logits=False
        )
        p_t = y_true * y_pred + (1 - y_true) * (1 - y_pred)
        focal_weight = self.alpha * tf.pow(1.0 - p_t, self.gamma)
        return focal_weight * bce

model.compile(optimizer="adam", loss=FocalLoss(gamma=2.0))$escape$,
  $escape$python$escape$,
