INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9ce4cc14-863f-4638-a091-4f9268a98fdc',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow GPU Acceleration — CUDA Devices, Tensor Placement & Mixed Precision$escape$,
  $escape$TensorFlow automatically places ops on the first available GPU, but explicit placement gives you control. Use `tf.device('/GPU:0')` context managers to force tensor creation and computation onto a specific CUDA device. Verify GPU visibility with `tf.config.list_physical_devices('GPU')` — if empty, your CUDA/cuDNN versions don't match the TensorFlow build.

For mixed precision training, enable the `mixed_float16` global policy via `tf.keras.mixed_precision.set_global_policy('mixed_float16')`. This stores weights in float32 but casts compute to float16, cutting VRAM usage roughly in half and boosting throughput on Ampere+ GPUs via Tensor Cores. One critical detail: wrap your optimizer with `LossScaleOptimizer` to prevent float16 gradient underflow — Keras does this automatically when the policy is set before model construction.

Use `tf.config.experimental.set_memory_growth(gpu, True)` to prevent TensorFlow from pre-allocating all GPU memory, which is essential when sharing a device across processes or Jupyter sessions.$escape$,
  $escape$import tensorflow as tf

# Confirm GPU availability
gpus = tf.config.list_physical_devices('GPU')
for gpu in gpus:
    tf.config.experimental.set_memory_growth(gpu, True)

# Enable mixed precision globally (before model construction)
tf.keras.mixed_precision.set_global_policy('mixed_float16')

# Explicit device placement
with tf.device('/GPU:0'):
    x = tf.constant([[1.0, 2.0], [3.0, 4.0]])  # created on GPU:0
    y = tf.matmul(x, x)

# Build model — optimizer auto-wrapped with LossScaleOptimizer
model = tf.keras.Sequential([tf.keras.layers.Dense(128, activation='relu')])
model.compile(optimizer='adam', loss='mse')$escape$,
  $escape$python$escape$,
