INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd6633401-62be-45a5-95b3-692559cac543',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Model Debugging — Gradient Flow, NaN Loss & Exploding/Vanishing Gradients$escape$,
  $escape$NaN loss almost always traces back to three sources: exploding gradients, a bad learning rate, or log(0) in your loss function. Start with `tf.debugging.check_numerics()` — wrap suspicious tensors to pinpoint the exact op where NaN first appears. For exploding gradients, apply gradient clipping via `optimizer = tf.keras.optimizers.Adam(clipnorm=1.0)` or manually clip with `tf.clip_by_global_norm(grads, 1.0)` before applying. Vanishing gradients are subtler — use `tf.GradientTape` with `tape.gradient(loss, model.trainable_variables)` and log gradient norms per layer. If early layers show near-zero norms, switch activations from `sigmoid` to `relu` or `swish`, or add batch normalization. TensorBoard's histogram dashboard (`tf.summary.histogram`) is your best visualization tool — log weight and gradient distributions each epoch to catch divergence early. For custom training loops, `tf.debugging.assert_all_finite(loss, 'Loss has NaN/Inf')` will hard-fail before corrupt gradients propagate through the graph.$escape$,
  $escape$import tensorflow as tf

optimizer = tf.keras.optimizers.Adam(learning_rate=1e-3, clipnorm=1.0)

@tf.function
def train_step(x, y):
    with tf.GradientTape() as tape:
        logits = model(x, training=True)
        loss = loss_fn(y, logits)
        tf.debugging.assert_all_finite(loss, 'NaN/Inf loss detected')

    grads = tape.gradient(loss, model.trainable_variables)
    grads, global_norm = tf.clip_by_global_norm(grads, 1.0)

    for i, (g, v) in enumerate(zip(grads, model.trainable_variables)):
        tf.summary.histogram(f'grad/{v.name}', g, step=optimizer.iterations)

    optimizer.apply_gradients(zip(grads, model.trainable_variables))
    return loss$escape$,
  $escape$python$escape$,
