INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '709cbf57-ed4d-431e-ba35-30a84d8d01e6',
  '00000000-0000-0000-0000-000000000001',
  $escape$TensorFlow Keras — Functional API, Custom Layers, and Training Loops$escape$,
  $escape$Keras in TensorFlow 2.x ships three model-building styles. Sequential is fine for straight pipelines, but the Functional API unlocks shared layers, multi-input/output graphs, and residual connections — you wire tensors explicitly, giving you a DAG rather than a stack. For anything Sequential can't express, subclass `tf.keras.Model` and define `call()` yourself.

Custom layers live in `tf.keras.layers.Layer`. Override `build()` to create weights lazily (shape-dependent init) and `call()` for the forward pass. Mark weights with `self.add_weight()` so Keras tracks them for gradient updates and serialization.

When `model.fit()` is too opaque — custom gradient clipping, auxiliary losses, multi-optimizer steps — drop into a manual training loop using `tf.GradientTape`. Call the model inside the tape context, compute your loss, then apply `optimizer.apply_gradients(zip(grads, model.trainable_variables))`. Pair this with `@tf.function` to JIT-compile the step for near-graph performance without abandoning Python control flow.$escape$,
  $escape$import tensorflow as tf

class ScaledDense(tf.keras.layers.Layer):
    def build(self, input_shape):
        self.w = self.add_weight(shape=(input_shape[-1], 64), initializer='glorot_uniform', trainable=True)
        self.scale = self.add_weight(shape=(), initializer='ones', trainable=True)

    def call(self, x):
        return tf.matmul(x, self.w) * self.scale

# Functional API model
inputs = tf.keras.Input(shape=(128,))
x = ScaledDense()(inputs)
outputs = tf.keras.layers.Dense(10, activation='softmax')(x)
model = tf.keras.Model(inputs, outputs)

optimizer = tf.keras.optimizers.Adam()
loss_fn = tf.keras.losses.SparseCategoricalCrossentropy()

@tf.function
def train_step(x_batch, y_batch):
    with tf.GradientTape() as tape:
        preds = model(x_batch, training=True)
        loss = loss_fn(y_batch, preds)
    grads = tape.gradient(loss, model.trainable_variables)
    optimizer.apply_gradients(zip(grads, model.trainable_variables))
    return loss$escape$,
  $escape$python$escape$,
